import React from 'react';

import './project.scss';
import Container from './container';

export default ({title, author, image, video, site, github, files, children}) => (
  <div className="project">
    <Container>
      <h1 className="project-title">
	{title} <span className="project-author">by {author}</span>
      </h1>

      {image &&
        <img className="project-media" src={image} alt="" />
      }
      {video &&
        <video className="project-media" autoPlay={true} loop={true} muted={true} playsInline={true}>
          <source src={video} type="video/mp4" />
        </video>
      }

      <div className="project-buttons">
	{site &&
	  <p><a className="button project-button" href={site} target="_blank">Try in browser</a></p>
	}
	{files &&
	  <p><a className="button project-button" href={files} target="_blank">Download</a></p>
	}
	{github &&
	  <p><a className="button project-button" href={github} target="_blank">GitHub</a></p>
	}
      </div>

      <div className="project-text">
	{children}
      </div>
    </Container>
  </div>
);
